const personen = $input.first().json;
const aufgaben = items.length > 1 ? $input.last().json : [];
const pList = Array.isArray(personen) ? personen : [personen];
const aList = Array.isArray(aufgaben) ? aufgaben : [aufgaben];

const APP_URL = $env.APP_URL || 'https://ludwig-a11y.github.io/halleluja-os/';
const today = new Date().toISOString().slice(0, 10);
const prioRank = { P1: 0, P2: 1, P3: 2 };

const results = [];

for (const p of pList) {
  if (!p.slack_id) continue;

  const meine = aList.filter(a => String(a.pid) === String(p.id));

  // Sortiere: aktive zuerst, dann Prio (P1>P2>P3), dann Deadline
  meine.sort((a, b) => {
    if (a.status === 'aktiv' && b.status !== 'aktiv') return -1;
    if (b.status === 'aktiv' && a.status !== 'aktiv') return 1;
    const pp = (prioRank[a.prio] ?? 3) - (prioRank[b.prio] ?? 3);
    if (pp !== 0) return pp;
    if (a.dl && b.dl) return a.dl.localeCompare(b.dl);
    if (a.dl) return -1;
    if (b.dl) return 1;
    return 0;
  });

  if (meine.length === 0) {
    results.push({
      json: {
        channel: p.slack_id,
        text: `☀️ Guten Morgen, ${p.name}!\n\nKeine offenen Aufgaben — genieß den Tag! 🎉\n<${APP_URL}|Halleluja OS öffnen>`
      }
    });
    continue;
  }

  const top = meine[0];
  const prioEmoji = top.prio === 'P1' ? '🔴' : top.prio === 'P2' ? '🟡' : top.prio === 'P3' ? '🔵' : '⚪';
  const statusHint = top.status === 'aktiv' ? ' _(läuft bereits)_' : '';

  let dlInfo = '';
  if (top.dl) {
    const dlDate = new Date(top.dl + 'T12:00:00');
    const diff = Math.ceil((dlDate - new Date(today + 'T12:00:00')) / 86400000);
    if (diff === 0) dlInfo = '⏰ Fällig: heute';
    else if (diff === 1) dlInfo = '⏰ Fällig: morgen';
    else if (diff < 0) dlInfo = '🔴 Überfällig seit ' + Math.abs(diff) + ' Tag' + (Math.abs(diff) > 1 ? 'en' : '');
    else dlInfo = '📅 Fällig in ' + diff + ' Tagen';
  }

  const deepLink = `${APP_URL}#task=${top.id}`;
  let msg = `☀️ Guten Morgen, ${p.name}!\n\n${prioEmoji} *Dein wichtigstes To-Do:*\n> *${top.titel}*${statusHint}`;
  if (dlInfo) msg += `\n> ${dlInfo}`;
  msg += `\n\n<${deepLink}|Hier starten →>`;

  const p1Count = meine.filter(a => a.prio === 'P1').length;
  const totalCount = meine.length;
  const summary = [];
  if (p1Count > 1) summary.push(p1Count + ' P1s offen');
  if (totalCount > 1) summary.push(totalCount + ' Aufgaben gesamt');
  if (summary.length) msg += `\n\n_${summary.join(' · ')}_`;

  results.push({ json: { channel: p.slack_id, text: msg } });
}

return results;
